/**
 * NHS UK Frontend library

 */
// Use a dynamic import so this file can be included as a normal <script>
// without requiring the script tag to be <script type="module">.
(async function() {
    try {
        const mod = await import('./nhsuk.min.js');
        if (mod && typeof mod.initAll === 'function') {
            try { mod.initAll(); } catch (e) { console.error('nhsuk initAll error', e); }
        }
    } catch (err) {
        console.error('Failed to load nhsuk frontend module:', err);
    }
})();
